#include<bits/stdc++.h>
using namespace std;
struct node{
    int d;
    int x;
}a[2000005];
bool cmp(node aa,node bb){
    return aa.d<bb.d;
}
int main() {
	int m, n,ans=0,i=1;
	cin >> m >> n;
	for(int i=1;i<=n;i++){
        cin>>a[i].d>>a[i].x;
    }
    sort(a+1,a+n+1,cmp);
    while(m>0){
        if(m<=a[i].x){
            ans+=(m*a[i].d);
            m=0;
        }else{
            ans+=a[i].d*a[i].x;
            m-=a[i].x;
        }
        i++;
    }
    cout<<ans;
	return 0;
}
